/**
* Kernel
* Executed on CPU using OpenMP
* Calculates the Euclidean distance from each record in the database to the target position
*/
void euclid_omp(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; ++globalId) {
        LatLong current_location = locations[globalId];
        distances[globalId] = (float)sqrt((lat - current_location.lat) * (lat - current_location.lat) + (lng - current_location.lng) * (lng - current_location.lng));
    }
}

/**
* This program finds the k-nearest neighbors
**/

int main(int argc, char* argv[])
{
	int    i=0;
	float lat = 0.0f, lng = 0.0f; // Initialize to defaults
	int quiet=0,timing=0,platform=0,device=0;

    Record *records = NULL;
    LatLong *locations = NULL;
    int numRecords = 0;

	char filename[100];
	int resultsCount=10;

    // parse command line
    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    // Load data using C-style array handling
    if (loadData(filename, &records, &locations, &numRecords)) {
        fprintf(stderr, "Failed to load data.\n");
        return 1;
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    //Pointers to host memory
	float *distances;

	/**
	* Allocate memory on host
	*/
	distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Memory allocation failed for distances.\n");
        free(records);
        free(locations);
        return 1;
    }

    /**
    * Execute kernel
    */

#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

    // Call the OpenMP version of the kernel
    euclid_omp(locations, distances, numRecords, lat, lng);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	// find the resultsCount least distances
    findLowest(records, distances, numRecords, resultsCount);

    // print out results
    if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
    }

    // Free allocated memory
    free(distances);
    free(records);
    free(locations);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
    return 0;
}

// Modified loadData to use C-style dynamic arrays
int loadData(char *filename, Record **records_ptr, LatLong **locations_ptr, int *numRecords_ptr){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum = 0;
    int capacity = 1000; // Initial capacity for dynamic arrays

    // Allocate initial memory for records and locations
    *records_ptr = (Record *)malloc(capacity * sizeof(Record));
    *locations_ptr = (LatLong *)malloc(capacity * sizeof(LatLong));
    if (!*records_ptr || !*locations_ptr) {
        fprintf(stderr, "Initial memory allocation failed for records/locations.\n");
        free(*records_ptr); // Free if partially allocated
        free(*locations_ptr);
        return 1; // Indicate failure
    }

    flist = fopen(filename, "r");
	if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        return 1;
    }

	while(fscanf(flist, "%s\n", dbname) == 1) {
        fp = fopen(dbname, "r");
        if(!fp) {
            fprintf(stderr, "Error opening database file: %s\n", dbname);
            // Continue to next file in list, or exit? Let's exit for now.
            fclose(flist);
            free(*records_ptr);
            free(*locations_ptr);
            return 1;
        }

        while(!feof(fp)){
            Record current_record;
            LatLong current_latLong;

            // Read the record string
            if (fgets(current_record.recString, REC_LENGTH, fp) == NULL) {
                if (feof(fp)) break; // End of file reached normally
                fprintf(stderr, "Error reading record from %s\n", dbname);
                fclose(fp);
                fclose(flist);
                free(*records_ptr);
                free(*locations_ptr);
                return 1;
            }

            // Remove trailing newline if present
            size_t len = strlen(current_record.recString);
            if (len > 0 && current_record.recString[len-1] == '\n') {
                current_record.recString[len-1] = '\0';
                len--; // Update length
            } else {
                // If no newline, it means the line was exactly REC_LENGTH-1 chars long and didn't end with newline
                // or it was longer and truncated. We need to consume the rest of the line.
                int c;
                while ((c = fgetc(fp)) != '\n' && c != EOF);
            }

            // Ensure we have enough characters for lat/lng parsing
            if (len < LATITUDE_POS + 5 + 5) {
                fprintf(stderr, "Record too short to parse lat/lng in %s: %s\n", dbname, current_record.recString);
                continue; // Skip this record
            }

            // Parse lat and long
            char substr[6];

            strncpy(substr, current_record.recString + LATITUDE_POS, 5);
            substr[5] = '\0';
            current_latLong.lat = atof(substr);

            strncpy(substr, current_record.recString + LATITUDE_POS + 5, 5);
            substr[5] = '\0';
            current_latLong.lng = atof(substr);

            // Resize arrays if capacity is reached
            if (recNum >= capacity) {
                capacity *= 2; // Double the capacity
                Record *new_records = (Record *)realloc(*records_ptr, capacity * sizeof(Record));
                LatLong *new_locations = (LatLong *)realloc(*locations_ptr, capacity * sizeof(LatLong));

                if (!new_records || !new_locations) {
                    fprintf(stderr, "Memory reallocation failed for records/locations.\n");
                    free(*records_ptr);
                    free(*locations_ptr);
                    fclose(fp);
                    fclose(flist);
                    return 1; // Indicate failure
                }
                *records_ptr = new_records;
                *locations_ptr = new_locations;
            }

            // Store the parsed data
            (*records_ptr)[recNum] = current_record;
            (*locations_ptr)[recNum] = current_latLong;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    *numRecords_ptr = recNum;

    // Optional: Shrink arrays to fit the actual number of records
    Record *final_records = (Record *)realloc(*records_ptr, recNum * sizeof(Record));
    LatLong *final_locations = (LatLong *)realloc(*locations_ptr, recNum * sizeof(LatLong));

    if (final_records) *records_ptr = final_records;
    if (final_locations) *locations_ptr = final_locations;

    return 0; // Indicate success
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec; // Use a temporary Record for swapping
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }
    // swap locations and distances
    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    // add distance to the min we just found
    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; // error
    strncpy(filename,argv[1],100);
    filename[99] = '\0'; // Ensure null termination
    char flag;

    for(i=2;i<argc;i++) { // Start from index 2 to skip filename
      if (argv[i][0]=='-') {// flag
        flag = argv[i][1];
          switch (flag) {
            case 'r': // number of results
              if (i + 1 < argc) {
                *r = atoi(argv[++i]);
              } else { return 1; } // Missing argument
              break;
            case 'l': // lat or lng
              if (i + 1 < argc) {
                if (argv[i][2]=='a') {//lat
                  *lat = atof(argv[++i]);
                }
                else if (argv[i][2]=='n') {//lng
                  *lng = atof(argv[++i]);
                } else { return 1; } // Invalid flag format like -ln
              } else { return 1; } // Missing argument
              break;
            case 'h': // help
              return 1;
            case 'q': // quiet
              *q = 1;
              break;
            case 't': // timing
              *t = 1;
              break;
            case 'p': // platform
              if (i + 1 < argc) {
                *p = atoi(argv[++i]);
              } else { return 1; } // Missing argument
              break;
            case 'd': // device
              if (i + 1 < argc) {
                *d = atoi(argv[++i]);
              } else { return 1; } // Missing argument
              break;
            default:
              // Unknown flag
              return 1;
        }
      } else {
          // Non-flag argument after the filename, treat as error
          return 1;
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) // both p and d must be specified if either are specified
      return 1;
    return 0;
}

